+    // ── BocpdRegime traits ────────────────────────────────────────
+
+    #[test]
+    fn regime_as_str_values() {
+        assert_eq!(BocpdRegime::Steady.as_str(), "steady");
+        assert_eq!(BocpdRegime::Burst.as_str(), "burst");
+        assert_eq!(BocpdRegime::Transitional.as_str(), "transitional");
