+
+    #[test]
+    fn regime_default_is_steady() {
+        assert_eq!(BocpdRegime::default(), BocpdRegime::Steady);
+    }
+
+    #[test]
+    fn regime_clone_copy() {
+        let r = BocpdRegime::Burst;
+        let r2 = r;
+        assert_eq!(r, r2);
+        let r3 = r.clone();
